def lcs_len(a,b):
    return longest_common_substring_length(a,b)

def robust_similarity(substring, candidate_text):
    # normalized LCS recall measure: LCS length divided by length of substring normalized
    s_norm = normalize_ar(substring)
    c_norm = normalize_ar(candidate_text)
    if not s_norm:
        return 0.0
    L = lcs_len(c_norm, s_norm)
    return L/len(s_norm)

